## File: `apps/web/lib/stores/chat-store.ts`

Follow the exact pattern from `sidebar-store.ts`: Zustand with persist middleware.

```typescript
import { create } from 'zustand';
import { persist } from 'zustand/middleware';

export interface ChatMessage {
  id: string;                    // crypto.randomUUID()
  role: 'user' | 'assistant';
  content: string;
  sources?: SourceItem[];        // from @gilbertus/api-client
  meta?: AskResponseMeta;        // from @gilbertus/api-client
  timestamp: string;             // new Date().toISOString()
  isLoading?: boolean;
  error?: string;
}

export interface Conversation {
  id: string;                    // crypto.randomUUID()
  title: string;
  createdAt: string;
  lastActive: string;
  messages: ChatMessage[];
}

interface ChatStore {
  conversations: Conversation[];
  activeConversationId: string | null;

  createConversation: () => string;
  deleteConversation: (id: string) => void;
  renameConversation: (id: string, title: string) => void;
  setActiveConversation: (id: string | null) => void;

  addUserMessage: (convId: string, content: string) => string;
  addAssistantMessage: (convId: string, content: string, sources?: SourceItem[], meta?: AskResponseMeta) => void;
  updateAssistantMessage: (convId: string, msgId: string, content: string, sources?: SourceItem[], meta?: AskResponseMeta) => void;
  setMessageLoading: (convId: string, msgId: string, loading: boolean) => void;
  setMessageError: (convId: string, msgId: string, error: string) => void;
}
```

Key implementation details:
- `persist` with name `'gilbertus-chat'`
- `createConversation`: generates UUID, title='Nowa rozmowa', pushes to conversations[], returns id, sets it as active
- `addUserMessage`: creates ChatMessage with role='user', pushes to conversation.messages, updates lastActive. Auto-set conversation title from first user message (first 60 chars + '...' if longer). Returns message id.
- `addAssistantMessage`: creates ChatMessage with role='assistant', sources, meta. Pushes to conversation.messages, updates lastActive.
- `updateAssistantMessage`: finds message by id, updates content/sources/meta, sets isLoading=false
- `setMessageLoading/Error`: find message, update field
- `deleteConversation`: remove from array. If was active, set activeConversationId to null.
- Conversations sorted by lastActive DESC in the getter/selector.
- Max 50 conversations — when creating new one, if length >= 50, remove the oldest (by lastActive).
- Import SourceItem and AskResponseMeta types from `@gilbertus/api-client` (will be available from P1T1).

