## File: `apps/web/lib/hooks/use-chat.ts`

'use client' hook that connects the Zustand store with the API client.

```typescript
import { useCallback, useRef } from 'react';
import { useChatStore } from '@/lib/stores/chat-store';
import { useRole } from '@gilbertus/rbac';
import { askGilbertus, getBriefToday, getAlerts, getCommitments, getMeetingPrep, postTimeline } from '@gilbertus/api-client';

export function useChat() {
  const store = useChatStore();
  const { roleLevel } = useRole();
  const abortRef = useRef<AbortController | null>(null);

  const sendMessage = useCallback(async (text: string, conversationId?: string) => {
    // 1. Create conversation if needed
    const convId = conversationId ?? store.activeConversationId ?? store.createConversation();
    store.setActiveConversation(convId);

    // 2. Add user message
    const msgId = store.addUserMessage(convId, text);

    // 3. Add placeholder assistant message (loading)
    const assistantMsgId = crypto.randomUUID();
    // Add empty loading message
    store.addAssistantMessage(convId, '', undefined, undefined);
    // Actually: create the message in loading state first
    // Implementation detail: addAssistantMessage should be called with loading state
    // OR: add a createLoadingMessage action

    // 4. Abort previous request if any
    abortRef.current?.abort();
    abortRef.current = new AbortController();

    // 5. Call /ask
    try {
      const response = await askGilbertus({
        query: text,
        top_k: 8,
        answer_length: roleLevel >= 60 ? 'long' : 'medium',
        channel: 'web',
        session_id: convId,
        debug: true,
        include_sources: true,
      }, abortRef.current.signal);

      // 6. Update assistant message with response
      store.updateAssistantMessage(convId, assistantMsgId, response.answer, response.sources, response.meta);
    } catch (err: any) {
      if (err.name === 'AbortError') return;
      store.setMessageError(convId, assistantMsgId, err.message ?? 'Błąd połączenia');
    }
  }, [store, roleLevel]);

  const handleQuickAction = useCallback(async (actionId: string, conversationId?: string) => {
    const convId = conversationId ?? store.activeConversationId ?? store.createConversation();
    store.setActiveConversation(convId);

    // Map action to label for user message display
    const labels: Record<string, string> = {
      brief: '/brief — Poranny brief',
      timeline: '/timeline — Ostatnie wydarzenia',
      'meeting-prep': '/meeting-prep — Przygotowanie na spotkanie',
      alerts: '/alerts — Aktywne alerty',
      commitments: '/commitments — Zobowiązania',
    };

    store.addUserMessage(convId, labels[actionId] ?? `/${actionId}`);

    const assistantMsgId = crypto.randomUUID();
    // Add loading assistant message...

    abortRef.current?.abort();
    abortRef.current = new AbortController();

    try {
      let answer: string;
      const signal = abortRef.current.signal;

      switch (actionId) {
        case 'brief': {
          const res = await getBriefToday(signal);
          answer = typeof res === 'string' ? res : JSON.stringify(res, null, 2);
          break;
        }
        case 'alerts': {
          const res = await getAlerts(signal);
          answer = typeof res === 'string' ? res : JSON.stringify(res, null, 2);
          break;
        }
        case 'commitments': {
          const res = await getCommitments(signal);
          answer = typeof res === 'string' ? res : JSON.stringify(res, null, 2);
          break;
        }
        case 'meeting-prep': {
          const res = await getMeetingPrep(signal);
          answer = typeof res === 'string' ? res : JSON.stringify(res, null, 2);
          break;
        }
        case 'timeline': {
          const res = await postTimeline({}, signal);
          answer = typeof res === 'string' ? res : JSON.stringify(res, null, 2);
          break;
        }
        default:
          answer = `Nieznana akcja: ${actionId}`;
      }

      store.updateAssistantMessage(convId, assistantMsgId, answer);
    } catch (err: any) {
      if (err.name === 'AbortError') return;
      store.setMessageError(convId, assistantMsgId, err.message ?? 'Błąd');
    }
  }, [store]);

  const abort = useCallback(() => {
    abortRef.current?.abort();
  }, []);

  return {
    ...store,
    sendMessage,
    handleQuickAction,
    abort,
  };
}
```

NOTE: The above is a design guide, not copy-paste code. The dev should:
1. Handle the assistant loading message pattern properly — the store needs a `addLoadingMessage(convId)` that returns the msgId, which gets updated later via `updateAssistantMessage`.
2. Ensure abort works correctly — if a new message is sent while previous is loading, the previous request should be aborted.
3. Quick action responses may be plain strings or objects — handle both by checking type and formatting accordingly.
4. The hook should be used in the chat page components to wire everything together.

Dependencies: Requires P1T1 (api-client types/functions) and P1T2 (chat store) to be complete.

