## File 2: `apps/web/app/(app)/chat/page.tsx`

Main chat page — shows either empty state (new conversation) or redirects to active conversation.

```tsx
'use client';

import { useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { useChat } from '@/lib/hooks/use-chat';
import { ChatSidebar, ChatHeader, ChatInput, MessageList, EmptyState } from '@gilbertus/ui';

export default function ChatPage() {
  const router = useRouter();
  const {
    conversations, activeConversationId, setActiveConversation,
    createConversation, deleteConversation, renameConversation,
    sendMessage, handleQuickAction,
  } = useChat();

  const activeConv = conversations.find(c => c.id === activeConversationId);

  const handleNewChat = () => {
    setActiveConversation(null);  // Show empty state
  };

  const handleSend = async (text: string) => {
    await sendMessage(text);
    // After first message, URL should update
    // But since we manage state in Zustand, just let it re-render
  };

  const handleSelectConversation = (id: string) => {
    setActiveConversation(id);
    router.push(`/chat/${id}`);
  };

  return (
    <>
      {/* Left sidebar */}
      <ChatSidebar
        conversations={conversations}
        activeId={activeConversationId}
        onSelect={handleSelectConversation}
        onNew={handleNewChat}
        onDelete={deleteConversation}
        onRename={renameConversation}
      />

      {/* Main area */}
      <div className='flex flex-1 flex-col overflow-hidden'>
        {activeConv ? (
          <>
            <ChatHeader
              title={activeConv.title}
              onRename={(t) => renameConversation(activeConv.id, t)}
            />
            <MessageList
              messages={activeConv.messages}
              onRetry={(msgId) => { /* re-send previous user message */ }}
            />
            <ChatInput
              onSend={handleSend}
              onQuickAction={(a) => handleQuickAction(a)}
              disabled={activeConv.messages.some(m => m.isLoading)}
            />
          </>
        ) : (
          <div className='flex flex-1 flex-col'>
            <div className='flex flex-1 items-center justify-center'>
              <EmptyState onQuickAction={(a) => handleQuickAction(a)} />
            </div>
            <ChatInput
              onSend={handleSend}
              onQuickAction={(a) => handleQuickAction(a)}
              placeholder='Zadaj pytanie Gilbertusowi...'
            />
          </div>
        )}
      </div>
    </>
  );
}
```

## File 3: `apps/web/app/(app)/chat/[id]/page.tsx`

Conversation-specific page — loads conversation by ID from URL.

```tsx
'use client';

import { useEffect } from 'react';
import { useParams, useRouter } from 'next/navigation';
import { useChatStore } from '@/lib/stores/chat-store';

export default function ConversationPage() {
  const { id } = useParams<{ id: string }>();
  const router = useRouter();
  const { setActiveConversation, conversations } = useChatStore();

  useEffect(() => {
    const conv = conversations.find(c => c.id === id);
    if (conv) {
      setActiveConversation(id);
    } else {
      // Conversation not found — redirect to /chat
      router.replace('/chat');
    }
  }, [id]);

  // The actual rendering is handled by the parent layout / ChatPage
  // This page just sets the active conversation ID
  // We need to render the same chat UI here
  // OPTION: redirect to /chat and let it handle active state
  // OR: duplicate the chat UI (not ideal)
  // BEST: Use the chat layout.tsx to render ChatSidebar + main area,
  //       and both page.tsx and [id]/page.tsx just set the active conversation.
  //       The layout reads activeConversationId from store.

  // Simplest approach: redirect to /chat after setting active
  router.replace('/chat');
  return null;
}
```

ALTERNATIVE (recommended): Move all the chat rendering into `layout.tsx` instead of `page.tsx`, and have both pages just set the activeConversationId. This avoids duplicate rendering logic.

The dev should choose the cleanest approach. The key requirement is:
- `/chat` → empty state or last active conversation
- `/chat/{id}` → that specific conversation
- Sidebar always visible with conversation list
- URL updates when switching conversations

